#include <bits/stdc++.h>
using namespace std;
long long a[11],b;
int main(){
    double n,c=0;
    cin>>n;
    for(int i=0;i<n;i++){
    	cin>>b;
        a[b]++;
        c+=b;
    }
    for(int i=0;i<11;i++){
        if(a[i]!=0){
            c-=i;
            break;
        }
    }
    for(int i=10;i>=0;i--){
        if(a[i]!=0){
            c-=i;
            break;
        }
    }
    double d=c/(n-2);
    printf("%.2lf",d);
    return 0;
}
